package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringReader;
import java.io.StringWriter;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

public class Gson_longAdapter_Test {

  private Method longAdapterMethod;

  @BeforeEach
  public void setUp() throws NoSuchMethodException {
    longAdapterMethod = Gson.class.getDeclaredMethod("longAdapter", LongSerializationPolicy.class);
    longAdapterMethod.setAccessible(true);
  }

  @Test
  public void testLongAdapter_withDefaultPolicy_returnsTypeAdaptersLong() throws Throwable {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.DEFAULT);
    assertSame(TypeAdapters.LONG, adapter);
  }

  @Test
  public void testLongAdapter_withNonDefaultPolicy_readNull() throws Throwable {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);

    JsonReader in = mock(JsonReader.class);
    when(in.peek()).thenReturn(JsonToken.NULL);

    Number result = adapter.read(in);
    verify(in).nextNull();
    assertNull(result);
  }

  @Test
  public void testLongAdapter_withNonDefaultPolicy_readLong() throws Throwable, IOException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);

    JsonReader in = mock(JsonReader.class);
    when(in.peek()).thenReturn(JsonToken.NUMBER);
    when(in.nextLong()).thenReturn(123L);

    Number result = adapter.read(in);
    assertEquals(123L, result);
  }

  @Test
  public void testLongAdapter_withNonDefaultPolicy_writeNull() throws Throwable, IOException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);

    JsonWriter out = mock(JsonWriter.class);
    adapter.write(out, null);
    verify(out).nullValue();
  }

  @Test
  public void testLongAdapter_withNonDefaultPolicy_writeValue() throws Throwable, IOException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);

    JsonWriter out = mock(JsonWriter.class);
    Number value = 456L;
    adapter.write(out, value);
    verify(out).value("456");
  }

  @Test
  public void testLongAdapter_withNonDefaultPolicy_writeValue_withDifferentNumber() throws Throwable, IOException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) longAdapterMethod.invoke(null, LongSerializationPolicy.STRING);

    JsonWriter out = mock(JsonWriter.class);
    Number value = 789; // Integer treated as Number
    adapter.write(out, value);
    verify(out).value("789");
  }
}
